async function enqueueIngestion(env, payload) {
  if (!env.redisUrl) {
    return {
      queued: false,
      reason: "Redis is not configured; source was ingested synchronously in demo mode.",
      payload
    };
  }
  const { Queue } = await Promise.resolve().then(() => __toESM(require_cjs()));
  const queue = new Queue("archmind-ingestion", {
    connection: {
      url: env.redisUrl
    }
  });
  const job = await queue.add("ingest-source", payload, {
    removeOnComplete: true,
    attempts: 3,
    backoff: {
      type: "exponential",
      delay: 1e4
    }
  });
  await queue.close();
  return {
    queued: true,
    jobId: job.id,
    payload
  };
}

